# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import Counter
import numpy as np
import pickle
from sklearn.ensemble import RandomForestClassifier
from sklearn.preprocessing import LabelEncoder
import os

app = Flask(__name__)

# Store labels and model
labels_db = {}
model = None
label_encoder = LabelEncoder()

@app.route('/label', methods=['POST'])
def add_label():
    data = request.get_json()
    image_id = data['image_id']
    annotator_id = data['annotator_id']
    label = data['label']
    
    if image_id not in labels_db:
        labels_db[image_id] = {}
    
    if annotator_id not in labels_db[image_id]:
        labels_db[image_id][annotator_id] = []
    
    labels_db[image_id][annotator_id].append(label)
    return jsonify({"status": "success"})

@app.route('/aggregate/<image_id>', methods=['GET'])
def aggregate_labels(image_id):
    if image_id not in labels_db:
        return jsonify({"error": "No labels found"}), 404
    
    annotator_labels = labels_db[image_id]
    all_labels = [label for labels in annotator_labels.values() for label in labels]
    
    # Majority voting
    label_counts = Counter(all_labels)
    majority_label = label_counts.most_common(1)[0][0]
    
    return jsonify({
        "image_id": image_id,
        "aggregated_label": majority_label,
        "label_counts": dict(label_counts)
    })

@app.route('/train', methods=['POST'])
def train_model():
    global model, label_encoder
    
    # Prepare training data
    X = []
    y = []
    
    for image_id, annotator_labels in labels_db.items():
        # Get majority vote for this image
        all_labels = [label for labels in annotator_labels.values() for label in labels]
        label_counts = Counter(all_labels)
        majority_label = label_counts.most_common(1)[0][0]
        
        # In a real system, you would extract features from images
        # Here we simulate feature extraction with random features
        X.append(np.random.rand(10))  # Simulated features
        y.append(majority_label)
    
    if len(X) == 0:
        return jsonify({"error": "No training data available"}), 400
    
    # Encode labels
    y_encoded = label_encoder.fit_transform(y)
    
    # Train model
    model = RandomForestClassifier(n_estimators=100, random_state=42)
    model.fit(X, y_encoded)
    
    return jsonify({"status": "model trained successfully"})

@app.route('/predict', methods=['POST'])
def predict():
    if model is None:
        return jsonify({"error": "Model not trained yet"}), 400
    
    data = request.get_json()
    features = np.array(data['features']).reshape(1, -1)
    
    prediction = model.predict(features)
    predicted_label = label_encoder.inverse_transform(prediction)[0]
    
    return jsonify({"predicted_label": predicted_label})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)